"use strict";(self.webpackChunkuuboyscy_engineering_logs=self.webpackChunkuuboyscy_engineering_logs||[]).push([[6882],{91013:(e,n,a)=>{a.r(n),a.d(n,{assets:()=>o,contentTitle:()=>d,default:()=>l,frontMatter:()=>r,metadata:()=>t,toc:()=>_});const t=JSON.parse('{"id":"GCP/BigQuery/BQML/bqml_sample","title":"BQML Sample: Purchase Propensity","description":"In this sample, we will build a machine learning model to predict: \\"Will this user make a purchase in the next 7 days?\\"","source":"@site/docs/GCP/BigQuery/BQML/02_bqml_sample.md","sourceDirName":"GCP/BigQuery/BQML","slug":"/GCP/BigQuery/BQML/bqml_sample","permalink":"/zh-Hant/docs/GCP/BigQuery/BQML/bqml_sample","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":2,"frontMatter":{},"sidebar":"tutorialSidebar","previous":{"title":"Introduction to BigQuery ML (BQML)","permalink":"/zh-Hant/docs/GCP/BigQuery/BQML/bqml_introduction"},"next":{"title":"Git Commands","permalink":"/zh-Hant/docs/category/git-commands"}}');var i=a(74848),s=a(28453);const r={},d="BQML Sample: Purchase Propensity",o={},_=[{value:"Step 1: Generate Mock Data",id:"step-1-generate-mock-data",level:2},{value:"Step 2: Feature Engineering (Prepare Data)",id:"step-2-feature-engineering-prepare-data",level:2},{value:"Step 3: Train the Model",id:"step-3-train-the-model",level:2},{value:"Step 4: Evaluate and Predict",id:"step-4-evaluate-and-predict",level:2}];function c(e){const n={code:"code",em:"em",h1:"h1",h2:"h2",header:"header",p:"p",pre:"pre",strong:"strong",...(0,s.R)(),...e.components},{Details:a}=n;return a||function(e,n){throw new Error("Expected "+(n?"component":"object")+" `"+e+"` to be defined: you likely forgot to import, pass, or provide it.")}("Details",!0),(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(n.header,{children:(0,i.jsx)(n.h1,{id:"bqml-sample-purchase-propensity",children:"BQML Sample: Purchase Propensity"})}),"\n",(0,i.jsxs)(n.p,{children:["In this sample, we will build a machine learning model to predict: ",(0,i.jsx)(n.strong,{children:'"Will this user make a purchase in the next 7 days?"'})]}),"\n",(0,i.jsx)(n.h2,{id:"step-1-generate-mock-data",children:"Step 1: Generate Mock Data"}),"\n",(0,i.jsxs)(n.p,{children:["First, we use a Python script to generate sample e-commerce data (like ",(0,i.jsx)(n.code,{children:"view_item"})," or ",(0,i.jsx)(n.code,{children:"add_to_cart"}),"). This creates a file called ",(0,i.jsx)(n.code,{children:"ga4_mock_data.json"}),".\n",(0,i.jsxs)(n.em,{children:["(You would load this JSON file into a BigQuery table named ",(0,i.jsx)(n.code,{children:"bqml_demo.analytics_events"}),".)"]})]}),"\n",(0,i.jsxs)(a,{children:[(0,i.jsx)("summary",{children:"Click here to view the Python Script"}),(0,i.jsx)(n.pre,{children:(0,i.jsx)(n.code,{className:"language-python",children:'import json\nimport random\nimport datetime\nimport uuid\n\n# Configuration\nNUM_USERS = 100\nSTART_DATE = datetime.date(2023, 1, 1)\nDAYS_TO_SIMULATE = 60\nOUTPUT_FILE = "ga4_mock_data.json"\n\n# Event Types\nEVENTS = ["session_start", "page_view", "view_item", "add_to_cart", "begin_checkout", "purchase"]\n\n# Items\nITEMS = [\n    {"item_id": "SKU_1001", "item_name": "T-Shirt Basic", "price": 20.0, "category": "Apparel"},\n    {"item_id": "SKU_1002", "item_name": "Jeans Slim", "price": 50.0, "category": "Apparel"},\n    {"item_id": "SKU_2001", "item_name": "Running Shoes", "price": 80.0, "category": "Footwear"},\n    {"item_id": "SKU_3001", "item_name": "Cap", "price": 15.0, "category": "Accessories"},\n    {"item_id": "SKU_4001", "item_name": "Backpack", "price": 45.0, "category": "Accessories"},\n]\n\ndef generate_user_data():\n    """Generates a list of events for a set of users with varying behaviors."""\n    \n    all_events = []\n    user_ids = [str(uuid.uuid4()) for _ in range(NUM_USERS)]\n    \n    # Assign personas\n    heavy_buyers = user_ids[:int(NUM_USERS*0.1)]\n    window_shoppers = user_ids[int(NUM_USERS*0.1):int(NUM_USERS*0.1)+int(NUM_USERS*0.3)]\n    bouncers = user_ids[int(NUM_USERS*0.4):]\n\n    for day_offset in range(DAYS_TO_SIMULATE):\n        current_date = START_DATE + datetime.timedelta(days=day_offset)\n        date_str = current_date.strftime("%Y%m%d")\n        \n        daily_active_users = []\n        \n        for uid in heavy_buyers:\n            if random.random() < 0.3: daily_active_users.append((uid, "buyer"))\n        for uid in window_shoppers:\n            if random.random() < 0.1: daily_active_users.append((uid, "shopper"))\n        for uid in bouncers:\n            if random.random() < 0.02: daily_active_users.append((uid, "bouncer"))\n\n        for uid, persona in daily_active_users:\n            ga_session_id = int(datetime.datetime.now().timestamp()) + random.randint(1, 100000)\n            base_timestamp_micros = int(datetime.datetime(\n                current_date.year, current_date.month, current_date.day,\n                random.randint(8, 22), random.randint(0, 59)\n            ).timestamp() * 1000000)\n\n            base_params = [\n                {"key": "ga_session_id", "value": {"int_value": ga_session_id}},\n                {"key": "page_title", "value": {"string_value": "Home Page"}}\n            ]\n\n            all_events.append({\n                "event_date": date_str,\n                "event_timestamp": base_timestamp_micros,\n                "event_name": "session_start",\n                "user_pseudo_id": uid,\n                "event_params": base_params\n            })\n            base_timestamp_micros += random.randint(1000, 5000000) \n\n            num_views = 0\n            if persona == "bouncer": num_views = random.randint(0, 1)\n            elif persona == "shopper": num_views = random.randint(2, 5)\n            elif persona == "buyer": num_views = random.randint(3, 8)\n\n            for _ in range(num_views):\n                item = random.choice(ITEMS)\n                all_events.append({\n                    "event_date": date_str,\n                    "event_timestamp": base_timestamp_micros,\n                    "event_name": "view_item",\n                    "user_pseudo_id": uid,\n                    "event_params": base_params + [\n                         {"key": "item_id", "value": {"string_value": item["item_id"]}},\n                         {"key": "price", "value": {"double_value": item["price"]}}\n                    ]\n                })\n                base_timestamp_micros += random.randint(5000000, 30000000)\n\n                atc_chance = 0.0\n                if persona == "shopper": atc_chance = 0.2\n                if persona == "buyer": atc_chance = 0.5\n                \n                if random.random() < atc_chance:\n                    all_events.append({\n                        "event_date": date_str,\n                        "event_timestamp": base_timestamp_micros,\n                        "event_name": "add_to_cart",\n                        "user_pseudo_id": uid,\n                        "event_params": base_params + [\n                             {"key": "item_id", "value": {"string_value": item["item_id"]}},\n                             {"key": "price", "value": {"double_value": item["price"]}}\n                        ]\n                    })\n                    base_timestamp_micros += random.randint(2000000, 10000000)\n\n            purchase_chance = 0.0\n            if persona == "buyer": purchase_chance = 0.4\n            \n            if random.random() < purchase_chance:\n                pkt_value = random.choice(ITEMS)["price"]\n                all_events.append({\n                    "event_date": date_str,\n                    "event_timestamp": base_timestamp_micros,\n                    "event_name": "purchase",\n                    "user_pseudo_id": uid,\n                    "event_params": base_params + [\n                         {"key": "currency", "value": {"string_value": "USD"}},\n                         {"key": "value", "value": {"double_value": pkt_value}}\n                    ]\n                })\n\n    return all_events\n\ndef main():\n    events = generate_user_data()\n    events.sort(key=lambda x: x["event_timestamp"])\n    with open(OUTPUT_FILE, "w") as f:\n        for event in events:\n            f.write(json.dumps(event) + "\\n")\n    print(f"Generated {len(events)} events in {OUTPUT_FILE}")\n\nif __name__ == "__main__":\n    main()\n'})})]}),"\n",(0,i.jsx)(n.h2,{id:"step-2-feature-engineering-prepare-data",children:"Step 2: Feature Engineering (Prepare Data)"}),"\n",(0,i.jsxs)(n.p,{children:["We need to convert the raw events into user behavior features. We look at their past 30 days of behavior to predict if they will buy later (this target outcome is called a ",(0,i.jsx)(n.code,{children:"label"}),")."]}),"\n",(0,i.jsx)(n.pre,{children:(0,i.jsx)(n.code,{className:"language-sql",children:"CREATE OR REPLACE TABLE bqml_demo.training_data AS\n\nWITH \n  config AS (\n    SELECT \n      DATE('2023-01-31') as training_end_date,  -- Data BEFORE this is used for features\n      DATE('2023-02-07') as prediction_end_date -- Data AFTER this is used for labels\n  ),\n\n  features AS (\n    SELECT\n      user_pseudo_id,\n      -- Recency: Days since the last event\n      DATE_DIFF((SELECT training_end_date FROM config), MAX(PARSE_DATE('%Y%m%d', CAST(event_date AS STRING))), DAY) as recency,\n      -- Frequency: Number of unique sessions\n      COUNT(DISTINCT (SELECT value.int_value FROM UNNEST(event_params) WHERE key = 'ga_session_id')) as frequency,\n      -- Product Views\n      COUNTIF(event_name = 'view_item') as view_item_count,\n      -- Cart Adds\n      COUNTIF(event_name = 'add_to_cart') as add_to_cart_count,\n      -- Item Value\n      AVG((SELECT value.double_value FROM UNNEST(event_params) WHERE key = 'price')) as avg_price_viewed\n    FROM `bqml_demo.analytics_events`\n    WHERE PARSE_DATE('%Y%m%d', CAST(event_date AS STRING)) <= (SELECT training_end_date FROM config)\n    GROUP BY user_pseudo_id\n  ),\n\n  labels AS (\n    SELECT\n      user_pseudo_id,\n      1 as will_purchase  -- Flag as 1 if they made a purchase\n    FROM `bqml_demo.analytics_events`\n    WHERE PARSE_DATE('%Y%m%d', CAST(event_date AS STRING)) BETWEEN \n          DATE_ADD((SELECT training_end_date FROM config), INTERVAL 1 DAY) \n          AND (SELECT prediction_end_date FROM config)\n      AND event_name = 'purchase'\n    GROUP BY user_pseudo_id\n  )\n\nSELECT\n  f.*,\n  IFNULL(l.will_purchase, 0) as label\nFROM features f\nLEFT JOIN labels l USING(user_pseudo_id);\n"})}),"\n",(0,i.jsx)(n.h2,{id:"step-3-train-the-model",children:"Step 3: Train the Model"}),"\n",(0,i.jsxs)(n.p,{children:["We train a ",(0,i.jsx)(n.strong,{children:"Logistic Regression"})," model. This is a common AI algorithm used to predict Yes/No outcomes. BigQuery will automatically handle the math in the background!"]}),"\n",(0,i.jsx)(n.pre,{children:(0,i.jsx)(n.code,{className:"language-sql",children:"CREATE OR REPLACE MODEL `bqml_demo.purchase_propensity_model`\nOPTIONS(\n  model_type='LOGISTIC_REG',\n  input_label_cols=['label'],\n  enable_global_explain=TRUE\n) AS\nSELECT\n  * EXCEPT(user_pseudo_id) -- User ID is just an identifier, not a predictive feature\nFROM\n  `bqml_demo.training_data`;\n"})}),"\n",(0,i.jsx)(n.h2,{id:"step-4-evaluate-and-predict",children:"Step 4: Evaluate and Predict"}),"\n",(0,i.jsx)(n.p,{children:"Once the model is ready, we can check how good it is and then start making predictions."}),"\n",(0,i.jsx)(n.p,{children:(0,i.jsx)(n.strong,{children:"1. Check Accuracy (Evaluate)"})}),"\n",(0,i.jsx)(n.pre,{children:(0,i.jsx)(n.code,{className:"language-sql",children:"SELECT *\nFROM ML.EVALUATE(MODEL `bqml_demo.purchase_propensity_model`,\n  (SELECT * FROM `bqml_demo.training_data`)\n);\n"})}),"\n",(0,i.jsxs)(n.p,{children:[(0,i.jsx)(n.strong,{children:"2. Make Predictions"}),"\nThis tells us the probability (from 0 to 1) that a specific user will buy something."]}),"\n",(0,i.jsx)(n.pre,{children:(0,i.jsx)(n.code,{className:"language-sql",children:"SELECT *\nFROM ML.PREDICT(MODEL `bqml_demo.purchase_propensity_model`,\n  (SELECT * FROM `bqml_demo.training_data`)\n);\n"})}),"\n",(0,i.jsxs)(n.p,{children:[(0,i.jsx)(n.strong,{children:"3. Find Feature Importance"}),"\nSee what drove the predictions. (e.g., adding to cart might be a strong sign of purchase)."]}),"\n",(0,i.jsx)(n.pre,{children:(0,i.jsx)(n.code,{className:"language-sql",children:"SELECT\n  processed_input,\n  weight\nFROM ML.WEIGHTS(MODEL `bqml_demo.purchase_propensity_model`)\nORDER BY ABS(weight) DESC;\n"})})]})}function l(e={}){const{wrapper:n}={...(0,s.R)(),...e.components};return n?(0,i.jsx)(n,{...e,children:(0,i.jsx)(c,{...e})}):c(e)}},28453:(e,n,a)=>{a.d(n,{R:()=>r,x:()=>d});var t=a(96540);const i={},s=t.createContext(i);function r(e){const n=t.useContext(s);return t.useMemo((function(){return"function"==typeof e?e(n):{...n,...e}}),[n,e])}function d(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:r(e.components),t.createElement(s.Provider,{value:n},e.children)}}}]);